 944→function buildTrussDetailWebTags(lineSegments, instanceGeometry) {
 945→  const spanMidpoint = (instanceGeometry?.metrics?.span || 0) / 2;
 946→  let webIndex = 0;
 947→
 948→  return lineSegments
 949→    .filter((segment) => segment.memberType === 'web' && segment.start && segment.end)
 950→    .map((segment) => {
 951→      webIndex += 1;
 952→
 953→      const start = createDetailPoint(segment.start);
 954→      const end = createDetailPoint(segment.end);
 955→      const dx = end.x - start.x;
 956→      const dy = end.y - start.y;
 957→      const length = Math.hypot(dx, dy);
 958→      if (length <= 1) return null;
 959→
 960→      const midpoint = {
 961→        x: (start.x + end.x) / 2,
 962→        y: (start.y + end.y) / 2,
 963→      };
 964→      let offset = { x: 0, y: 0 };
 965→
 966→      if (Math.abs(dx) <= 1e-6) {
 967→        offset = {
 968→          x: midpoint.x < spanMidpoint ? -DETAIL_WEB_TAG_OFFSET : DETAIL_WEB_TAG_OFFSET,
 969→          y: 0,
 970→        };
 971→      } else {
 972→        const normal = { x: -dy / length, y: dx / length };
 973→        const tangent = { x: dx / length, y: dy / length };
 974→        const outwardNormal = selectOutwardNormal(normal, midpoint, spanMidpoint);
 975→        const tangentShift = (webIndex % 2 === 0 ? 1 : -1) * DETAIL_WEB_TAG_TANGENT_SHIFT;
 976→        offset = {
 977→          x: (outwardNormal.x * DETAIL_WEB_TAG_OFFSET) + (tangent.x * tangentShift),
 978→          y: (outwardNormal.y * DETAIL_WEB_TAG_OFFSET) + (tangent.y * tangentShift),
 979→        };
 980→      }
 981→
 982→      return createDetailTag(
 983→        `${instanceGeometry.instance.id}_detail_web_${webIndex}`,
 984→        [`W${webIndex} ${formatMeasurement(length)}`],
 985→        {
 986→          x: midpoint.x + offset.x,
 987→          y: midpoint.y + offset.y,
 988→        },
 989→        {
 990→          angle: 0,
 991→          sourceType: 'truss_web',
 992→          sourceId: segment.id,
 993→          measurementValue: length,
 994→          leaderLine: {
 995→            start: midpoint,
 996→            end: {
 997→              x: midpoint.x + (offset.x * 0.72),
 998→              y: midpoint.y + (offset.y * 0.72),
 999→            },
1000→          },
1001→        }
1002→      );
1003→    })
1004→    .filter(Boolean);
1005→}
1006→
1007→function buildTopChordRuns(instanceGeometry) {
1008→  return (instanceGeometry?.topChordRuns || [])
1009→    .map((run) => {
1010→      const points = (run.points || []).filter((point) => (
1011→        Number.isFinite(point?.x) && Number.isFinite(point?.z)
1012→      ));
1013→      if (points.length < 2) return null;
1014→      return {
1015→        id: run.id || run.side || 'main',
1016→        measurementCurve: run.measurementCurve || null,
1017→        points,
1018→        start: points[0],
1019→        end: points[points.length - 1],
1020→      };
1021→    })
1022→    .filter(Boolean);
1023→}
1024→
1025→function buildTrussDetailTopChordTags(instanceGeometry) {
1026→  return buildTopChordRuns(instanceGeometry)
1027→    .map((run, index) => {
1028→      const midpointSample = sampleTopChordRunMidpoint(run);
1029→      if (!midpointSample?.point || !midpointSample?.tangent) return null;
1030→
1031→      const detailTangent = {
1032→        x: midpointSample.tangent.x,
1033→        y: -midpointSample.tangent.z,
1034→      };
1035→      const tangentLength = Math.hypot(detailTangent.x, detailTangent.y);
1036→      const length = getTopChordRunLength(run);
1037→      if (length <= 1 || tangentLength <= 1e-6) return null;
1038→
1039→      const midpoint = {
1040→        x: midpointSample.point.x,
1041→        y: -midpointSample.point.z,
1042→      };
1043→      const outwardNormal = {
1044→        x: detailTangent.y / tangentLength,
1045→        y: -detailTangent.x / tangentLength,
1046→      };
1047→
1048→      return createDetailTag(
1049→        `${instanceGeometry.instance.id}_detail_top_chord_${run.id}`,
1050→        [`TC${index + 1} ${formatMeasurement(length)}`],
1051→        {
1052→          x: midpoint.x + (outwardNormal.x * DETAIL_TOP_CHORD_TAG_OFFSET),
1053→          y: midpoint.y + (outwardNormal.y * DETAIL_TOP_CHORD_TAG_OFFSET),
1054→        },
1055→        {
1056→          angle: 0,
1057→          sourceType: 'truss_top_chord',
1058→          sourceId: run.id,
1059→          measurementValue: length,
1060→          leaderLine: {
1061→            start: midpoint,
1062→            end: {
1063→              x: midpoint.x + (outwardNormal.x * DETAIL_TOP_CHORD_TAG_OFFSET * 0.78),
1064→              y: midpoint.y + (outwardNormal.y * DETAIL_TOP_CHORD_TAG_OFFSET * 0.78),
1065→            },
1066→          },
1067→        }
1068→      );
1069→    })
1070→    .filter(Boolean);
1071→}
