1073→export function getTrussInstanceLabel(trussSystem, instance, index = 0) {
1074→  const profile = buildTrussProfile(instance);
1075→  return `${trussSystem?.name || 'Truss System'} · ${profile.trussType.name} ${index + 1}`;
1076→}
