1078→export function buildTrussInstanceGeometry(trussSystem, instance) {
1079→  const sourceSystem = trussSystem && (trussSystem.trussInstances || []).some((entry) => entry.id === instance?.id)
1080→    ? trussSystem
1081→    : {
1082→        ...(trussSystem || {}),
1083→        trussInstances: instance ? [instance] : [],
1084→      };
1085→  const systemGeometry = buildTrussSystemGeometry(sourceSystem);
1086→  return systemGeometry.instances.find((entry) => entry.instance.id === instance?.id) || null;
1087→}
