1089→export function buildTrussSystemGeometry(trussSystem) {
1090→  const baseElevation = trussSystem?.baseElevation || 0;
1091→  const rawInstances = (trussSystem?.trussInstances || []).map((instance) => buildRawTrussInstanceGeometry(trussSystem, instance));
1092→  const transform = createSystemTransform(trussSystem, rawInstances, baseElevation);
1093→  const instances = rawInstances
1094→    .map((instanceGeometry) => transformInstanceGeometry(instanceGeometry, transform, baseElevation))
1095→    .map((instanceGeometry) => ({
1096→      ...instanceGeometry,
1097→      ...buildInstancePurlinGeometry(trussSystem, instanceGeometry, trussSystem?.purlinSystem),
1098→    }));
1099→  const allPlanPoints = instances.flatMap((entry) => ([
1100→    ...entry.copies.flatMap((copy) => [copy.overallStartPoint, copy.overallEndPoint]),
1101→    ...(entry.purlinSegments || []).flatMap((segment) => ([
1102→      { x: segment.startWorld.x, y: segment.startWorld.y },
1103→      { x: segment.endWorld.x, y: segment.endWorld.y },
1104→    ])),
1105→  ]));
1106→  const purlinSegments = instances.flatMap((entry) => entry.purlinSegments || []);
1107→
1108→  return {
1109→    trussSystem,
1110→    transform,
1111→    instances,
1112→    purlinSegments,
1113→    planBounds: createBounds(allPlanPoints.map((point) => ({
1114→      x: point.x,
1115→      y: point.y,
1116→      elevation: baseElevation,
1117→    }))),
1118→  };
1119→}
