1121→export function buildFloorTrussGeometry(trussSystems = []) {
1122→  const systems = trussSystems.map((trussSystem) => buildTrussSystemGeometry(trussSystem));
1123→  const allPoints = systems.flatMap((system) => ([
1124→    ...system.instances.flatMap((entry) => entry.copies.flatMap((copy) => [copy.overallStartPoint, copy.overallEndPoint])),
1125→    ...system.purlinSegments.flatMap((segment) => ([
1126→      { x: segment.startWorld.x, y: segment.startWorld.y },
1127→      { x: segment.endWorld.x, y: segment.endWorld.y },
1128→    ])),
1129→  ]));
1130→
1131→  return {
1132→    systems,
1133→    bounds: createBounds(allPoints.map((point) => ({ x: point.x, y: point.y, elevation: 0 }))),
1134→  };
1135→}
