1137→export function buildTrussDetailScene(trussSystem, trussInstanceId = null) {
1138→  const systemGeometry = buildTrussSystemGeometry(trussSystem);
1139→  const activeInstance = trussInstanceId
1140→    ? systemGeometry.instances.find((entry) => entry.instance.id === trussInstanceId)
1141→    : systemGeometry.instances[0] || null;
1142→  if (!activeInstance) return null;
1143→
1144→  const nodeMap = new Map(activeInstance.nodes.map((node) => [node.id, node]));
1145→  const lineSegments = activeInstance.members.map((member) => ({
1146→    id: member.id,
1147→    memberType: member.memberType,
1148→    start: nodeMap.get(member.startNodeId),
1149→    end: nodeMap.get(member.endNodeId),
1150→  }));
1151→  const purlinMarkers = (activeInstance.purlinAttachments || [])
1152→    .map((attachment) => createDetailPurlinMarker(attachment))
1153→    .filter(Boolean);
1154→  const detailAnnotations = buildTrussDetailDimensions(activeInstance);
1155→  const topChordTags = buildTrussDetailTopChordTags(activeInstance);
1156→  const webTags = buildTrussDetailWebTags(lineSegments, activeInstance);
1157→  const bounds = extendDetailBounds(
1158→    activeInstance.detailBounds,
1159→    detailAnnotations.dimensions,
1160→    [...detailAnnotations.tags, ...topChordTags, ...webTags]
1161→  );
1162→
1163→  return {
1164→    title: getTrussInstanceLabel(trussSystem, activeInstance.instance),
1165→    instanceGeometry: activeInstance,
1166→    nodeMap,
1167→    lineSegments,
1168→    purlinMarkers,
1169→    dimensions: detailAnnotations.dimensions,
1170→    tags: detailAnnotations.tags,
1171→    topChordTags,
1172→    webTags,
1173→    bounds,
1174→  };
1175→}
