1177→export function getTrussSystemPurlinTotalLength(trussSystemOrGeometry) {
1178→  const systemGeometry = trussSystemOrGeometry?.instances && trussSystemOrGeometry?.trussSystem
1179→    ? trussSystemOrGeometry
1180→    : buildTrussSystemGeometry(trussSystemOrGeometry);
1181→
1182→  return Math.max(
1183→    0,
1184→    ...systemGeometry.instances.flatMap((entry) => (
1185→      (entry.purlinRuns || []).map((run) => measurePurlinRunLength(run))
1186→    ))
1187→  );
1188→}
