1190→export function buildTrussPreviewObjects(trussSystem) {
1191→  return buildTrussSystemGeometry(trussSystem).instances.flatMap((entry) => ([
1192→    ...entry.copies.flatMap((copy) => copy.members.map((member) => createSegmentDescriptor(
1193→      `${entry.instance.id}_${copy.index}_${member.id}`,
1194→      trussSystem,
1195→      entry.instance,
1196→      member,
1197→      copy
1198→    ))),
1199→    ...(entry.purlinSegments || []).map((segment) => createPurlinSegmentDescriptor(segment, trussSystem, entry.instance)),
1200→  ]));
