1203→export function hitTestTrussInstance(trussSystem, instance, point, tolerance) {
1204→  const geometry = buildTrussInstanceGeometry(trussSystem, instance);
1205→  for (const copy of geometry.copies) {
1206→    if (distanceToSegment(point, copy.overallStartPoint, copy.overallEndPoint) <= tolerance) {
1207→      return true;
1208→    }
1209→  }
1210→  return false;
1211→}
